SELECT ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM atom WHERE molecule_id = (SELECT molecule_id FROM molecule WHERE label = 'TR206')), 4) 
FROM atom 
WHERE molecule_id = (SELECT molecule_id FROM molecule WHERE label = 'TR206') AND element = 'H';

